1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	};
5	
6	export type QuoteStep = { kind: "quote"; items: Item[] };
7	
8	export type Scenario = {
9	  customer: { yearsWithMHPCO: number };
10	  steps: QuoteStep[];
11	};
12	
13	export type ScenarioResult = {
14	  results: unknown[];
15	};
16	
17	const COMPONENT_BASE_PREMIUM = 25;
18	
19	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: COMPONENT_BASE_PREMIUM,
25	  moonstone: COMPONENT_BASE_PREMIUM,
26	};
27	
28	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
29	const PROCESSING_FEE = 5;
30	
31	function basePremiumForItem(item: Item): number {
32	  return BASE_PREMIUM_BY_ITEM[item.kind];
33	}
34	
35	type QuoteResult = { kind: "quote"; premium: number };
36	
37	const BUILDING_BLOCK_BASE_PREMIUM = 60;
38	const BUILDING_BLOCK_SIZE = 3;
39	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
40	
41	type ItemGroup = { kind: Item["kind"]; items: Item[] };
42	
43	function groupByKind(items: Item[]): ItemGroup[] {
44	  const groups = new Map<Item["kind"], Item[]>();
45	  for (const item of items) {
46	    const group = groups.get(item.kind) ?? [];
47	    group.push(item);
48	    groups.set(item.kind, group);
49	  }
50	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
51	}
52	
53	function isBuildingBlock(group: ItemGroup): boolean {
54	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
55	}
56	
57	function basePremiumForGroup(group: ItemGroup): number {
58	  if (isBuildingBlock(group)) {
59	    return BUILDING_BLOCK_BASE_PREMIUM;
60	  }
61	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
62	}
63	
64	function basePremiumForItems(items: Item[]): number {
65	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
66	}
67	
68	function quoteStep(step: QuoteStep): QuoteResult {
69	  const basePremium = basePremiumForItems(step.items);
70	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
71	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
72	  return { kind: "quote", premium };
73	}
74	
75	export function processScenario(scenario: Scenario): ScenarioResult {
76	  const results = scenario.steps.map(quoteStep);
77	  return { results };
78	}
